// Custom distribution ZIP task for easy distribution without Gradle
// Note: The 'application' plugin provides its own 'distZip' task, so we use a different name
tasks.register<Zip>("packageDist") {
    dependsOn(tasks.shadowJar)
    
    group = "distribution"
    description = "Creates a standalone distribution ZIP containing the fat JAR and startup scripts"
    
    val distBaseName = "ful"
    archiveBaseName.set(distBaseName)
    archiveVersion.set(fulVersion)
    destinationDirectory.set(layout.buildDirectory.dir("distributions"))
    
    // Create a top-level directory in the ZIP
    val topDir = "$distBaseName-$fulVersion"
    
    // Include the shadow JAR
    from(tasks.shadowJar.flatMap { it.archiveFile }) {
        into(topDir)
    }
    
    // Include startup scripts
    from("${rootProject.projectDir}/scripts/dist") {
        include("ful", "ful.bat", "README.md")
        into(topDir)
        // Set executable permission for Unix script
        filesMatching("ful") {
            mode = 0b111101101 // 0755 in octal
        }
    }
    
    // Include config example
    from("${rootProject.projectDir}/config.example.json") {
        into(topDir)
    }
    
    // Include LICENSE
    from("${rootProject.projectDir}/LICENSE") {
        into(topDir)
    }
    
    // Include NOTICE if it exists
    from("${rootProject.projectDir}") {
        include("NOTICE")
        into(topDir)
    }
    
    doLast {
        println("Distribution ZIP created: ${archiveFile.get().asFile.absolutePath}")
    }
}

// Alias for convenience: ./gradlew distZip will build the custom package
tasks.named("distZip") {
    dependsOn("packageDist")
}

// Generate SHA256 checksum files for distribution artifacts
tasks.register("distChecksum") {
    dependsOn("packageDist", "signReleaseArtifacts")
    
    group = "distribution"
    description = "Generates SHA256 checksum files for distribution artifacts"
    
    val packageDistTask = tasks.named<Zip>("packageDist")
    val shadowJarTask = tasks.shadowJar
    
    // Declare inputs for up-to-date checking
    inputs.files(packageDistTask.map { it.archiveFile })
    inputs.files(shadowJarTask.map { it.archiveFile })
    
    // Declare outputs
    val distDir = layout.buildDirectory.dir("distributions")
    outputs.dir(distDir)
    
    doLast {
        @Suppress("PLATFORM_CLASS_MAPPED_TO_KOTLIN")
        fun generateChecksum(file: File): String {
            val md = (Class.forName("java.security.MessageDigest")
                .getMethod("getInstance", String::class.java)
                .invoke(null, "SHA-256")) as java.security.MessageDigest
            val bytes = file.readBytes()
            val hash = md.digest(bytes)
            return hash.fold("") { acc, b -> acc + "%02x".format(b) }
        }
        
        fun writeChecksumFile(targetFile: File) {
            if (!targetFile.exists()) {
                println("Warning: Target file does not exist: ${targetFile.absolutePath}")
                return
            }
            
            val checksum = generateChecksum(targetFile)
            val checksumFile = File(targetFile.absolutePath + ".sha256")
            // Format: SHA256SUM  filename (two spaces, filename only - not path)
            checksumFile.writeText("$checksum  ${targetFile.name}\n")
            println("Checksum generated: ${checksumFile.absolutePath}")
        }
        
        val distDirFile = distDir.get().asFile
        
        // Generate checksum for ZIP
        val zipFile = packageDistTask.get().archiveFile.get().asFile
        writeChecksumFile(zipFile)
        
        // Copy shadow JAR to distributions folder and generate checksum
        val jarFile = shadowJarTask.get().archiveFile.get().asFile
        if (jarFile.exists()) {
            val destJarFile = File(distDirFile, jarFile.name)
            jarFile.copyTo(destJarFile, overwrite = true)
            println("JAR copied: ${destJarFile.absolutePath}")
            writeChecksumFile(destJarFile)
        }

        fun copySignatureFile(targetFile: File) {
            val signatureFile = File(targetFile.absolutePath + ".asc")
            if (!signatureFile.exists()) {
                println("Warning: Signature file does not exist: ${signatureFile.absolutePath}")
                return
            }
            val destSignatureFile = File(distDirFile, signatureFile.name)
            if (signatureFile.absolutePath == destSignatureFile.absolutePath) {
                return
            }
            signatureFile.copyTo(destSignatureFile, overwrite = true)
            println("Signature copied: ${destSignatureFile.absolutePath}")
        }

        // Copy signatures for ZIP and JAR into the distribution folder
        copySignatureFile(zipFile)
        if (jarFile.exists()) {
            copySignatureFile(jarFile)
        }
        
        println("All release artifacts saved to: ${distDirFile.absolutePath}")
    }
}

