val inMemorySigningKey =
    providers.environmentVariable("ORG_GRADLE_PROJECT_signingKey").orNull
        ?: providers.environmentVariable("GPG_PRIVATE_KEY").orNull
val inMemorySigningPassphrase =
    providers.environmentVariable("ORG_GRADLE_PROJECT_signingPassword").orNull
        ?: providers.environmentVariable("GPG_PASSPHRASE").orNull
val signingKeyName = providers.environmentVariable("SIGNING_GNUPG_KEY_NAME").orNull
val signingPassphrase = providers.environmentVariable("SIGNING_GNUPG_PASSPHRASE").orNull
val signingEnabled = !inMemorySigningKey.isNullOrBlank() || !signingKeyName.isNullOrBlank()
if (!signingKeyName.isNullOrBlank()) {
    extra["signing.gnupg.keyName"] = signingKeyName
}
if (!signingPassphrase.isNullOrBlank()) {
    extra["signing.gnupg.passphrase"] = signingPassphrase
}

signing {
    if (!inMemorySigningKey.isNullOrBlank()) {
        useInMemoryPgpKeys(inMemorySigningKey, inMemorySigningPassphrase)
    } else {
        useGpgCmd()
    }
    isRequired = signingEnabled
    sign(
        tasks.shadowJar.get(),
        tasks.named<Zip>("packageDist").get()
    )
}

tasks.withType<Sign> {
    onlyIf { signingEnabled }
}

tasks.register("signReleaseArtifacts") {
    dependsOn(tasks.named("signShadowJar"), tasks.named("signPackageDist"))
}
